 * @brief configuration for this traffic rules object
 */
const Configuration& configuration() const { return config_; }

auto getPathsForNormalOrIsolatedLanelet = [&](const lanelet::ConstLanelet & lanelet) {
  // if lanelet is not isolated, return normal possible paths
  if (!isIsolatedLanelet(lanelet, routing_graph_ptr_)) {
    return routing_graph_ptr_->possiblePaths(lanelet, possible_params);
  }
  // if lanelet is isolated, check if it has enough length
  if (!validateIsolatedLaneletLength(lanelet, object, validate_time_horizon)) {
    return lanelet::routing::LaneletPaths{};
  } else {
    // if lanelet has enough length, return possible paths
    return getPossiblePathsForIsolatedLanelet(lanelet);
  }
};

bool isIsolatedLanelet(
  const lanelet::ConstLanelet & lanelet, lanelet::routing::RoutingGraphPtr & graph)
{
  const auto & following_lanelets = graph->following(lanelet);
  const auto & left_lanelets = graph->lefts(lanelet);
  const auto & right_lanelets = graph->rights(lanelet);
  return left_lanelets.empty() && right_lanelets.empty() && following_lanelets.empty();
}

bool validateIsolatedLaneletLength(
  const lanelet::ConstLanelet & lanelet, const TrackedObject & object, const double prediction_time)
{
  // get closest center line point to object
  const auto & center_line = lanelet.centerline2d();
  const auto & obj_pos = object.kinematics.pose_with_covariance.pose.position;
  const lanelet::BasicPoint2d obj_point(obj_pos.x, obj_pos.y);
  // get end point of the center line
  const auto & end_point = center_line.back();
  // calc approx distance between closest point and end point
  const double approx_distance = lanelet::geometry::distance2d(obj_point, end_point);
  // calc min length for prediction
  const double abs_speed = std::hypot(
    object.kinematics.twist_with_covariance.twist.linear.x,
    object.kinematics.twist_with_covariance.twist.linear.y);
  const double min_length = abs_speed * prediction_time;
  return approx_distance > min_length;
}

auto distance2d(const Geometry1T& p1, const Geometry2T& p2)
    -> std::enable_if_t<internal::isTrivialDistance<Geometry1T, Geometry2T>(), double> {
  return distance(internal::GetGeometry<Geometry1T>::twoD(p1), internal::GetGeometry<Geometry2T>::twoD(p2));
}

lanelet::routing::LaneletPaths getPossiblePathsForIsolatedLanelet(
  const lanelet::ConstLanelet & lanelet)
{
  lanelet::ConstLanelets possible_lanelets;
  possible_lanelets.push_back(lanelet);
  lanelet::routing::LaneletPaths possible_paths;
  // need to initialize path with constant lanelets
  lanelet::routing::LaneletPath possible_path(possible_lanelets);
  possible_paths.push_back(possible_path);
  return possible_paths;
}

auto getLeftOrRightLanelets = [&](
                                const lanelet::ConstLanelet & lanelet,
                                const bool get_left) -> std::optional<lanelet::ConstLanelet> {
  const auto opt =
    get_left ? routing_graph_ptr_->left(lanelet) : routing_graph_ptr_->right(lanelet);
  if (!!opt) {
    return *opt;
  }
  if (!consider_only_routable_neighbours_) {
    const auto adjacent = get_left ? routing_graph_ptr_->adjacentLeft(lanelet)
                                   : routing_graph_ptr_->adjacentRight(lanelet);
    if (!!adjacent) {
      return *adjacent;
    }
    // search for unconnected lanelet
    const auto unconnected_lanelets =
      get_left ? getLeftLineSharingLanelets(lanelet, lanelet_map_ptr_)
               : getRightLineSharingLanelets(lanelet, lanelet_map_ptr_);
    // just return first candidate of unconnected lanelet for now
    if (!unconnected_lanelets.empty()) {
      return unconnected_lanelets.front();
    }
  }

  // if no candidate lanelet found, return empty
  return std::nullopt;
};

lanelet::ConstLanelets getLeftLineSharingLanelets(
  const lanelet::ConstLanelet & current_lanelet, const lanelet::LaneletMapPtr & lanelet_map_ptr)
{
  lanelet::ConstLanelets
    output_lanelets;  // create an empty container of type lanelet::ConstLanelets

  // step1: look for lane sharing current left bound
  lanelet::Lanelets left_lane_candidates =
    lanelet_map_ptr->laneletLayer.findUsages(current_lanelet.leftBound());
  for (auto & candidate : left_lane_candidates) {
    // exclude self lanelet
    if (candidate == current_lanelet) continue;
    // if candidate has linestring as right bound, assign it to output
    if (candidate.rightBound() == current_lanelet.leftBound()) {
      output_lanelets.push_back(candidate);
    }
  }
  return output_lanelets;  // return empty
}

Maneuver MapBasedPredictionNode::predictObjectManeuver(
  const std::string & object_id, const geometry_msgs::msg::Pose & object_pose,
  const LaneletData & current_lanelet_data, const double object_detected_time)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  // calculate maneuver
  const auto current_maneuver = [&]() {
    if (lane_change_detection_method_ == "time_to_change_lane") {
      return predictObjectManeuverByTimeToLaneChange(
        object_id, current_lanelet_data, object_detected_time);
    } else if (lane_change_detection_method_ == "lat_diff_distance") {
      return predictObjectManeuverByLatDiffDistance(
        object_id, object_pose, current_lanelet_data, object_detected_time);
    }
    throw std::logic_error("Lane change detection method is invalid.");
  }();

  if (road_users_history_.count(object_id) == 0) {
    return current_maneuver;
  }
  auto & object_info = road_users_history_.at(object_id);

  // update maneuver in object history
  if (!object_info.empty()) {
    object_info.back().one_shot_maneuver = current_maneuver;
  }

  // decide maneuver considering previous results
  if (object_info.size() < 2) {
    object_info.back().output_maneuver = current_maneuver;
    return current_maneuver;
  }
  // NOTE: The index of previous maneuver is not object_info.size() - 1
  const auto prev_output_maneuver =
    object_info.at(static_cast<int>(object_info.size()) - 2).output_maneuver;

  for (int i = 0;
       i < std::min(num_continuous_state_transition_, static_cast<int>(object_info.size())); ++i) {
    const auto & tmp_maneuver =
      object_info.at(static_cast<int>(object_info.size()) - 1 - i).one_shot_maneuver;
    if (tmp_maneuver != current_maneuver) {
      object_info.back().output_maneuver = prev_output_maneuver;
      return prev_output_maneuver;
    }
  }

  object_info.back().output_maneuver = current_maneuver;
  return current_maneuver;
}

Maneuver MapBasedPredictionNode::predictObjectManeuverByTimeToLaneChange(
  const std::string & object_id, const LaneletData & current_lanelet_data,
  const double /*object_detected_time*/)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  // Step1. Check if we have the object in the buffer
  if (road_users_history_.count(object_id) == 0) {
    return Maneuver::LANE_FOLLOW;
  }

  const std::deque<RoadUser> & object_info = road_users_history_.at(object_id);

  // Step2. Check if object history length longer than history_time_length
  const int latest_id = static_cast<int>(object_info.size()) - 1;
  // object history is not long enough
  if (latest_id < 1) {
    return Maneuver::LANE_FOLLOW;
  }

  // Step3. get object lateral kinematics
  const auto & latest_info = object_info.at(static_cast<size_t>(latest_id));

  bool not_found_corresponding_lanelet = true;
  double left_dist, right_dist;
  double v_left_filtered, v_right_filtered;
  if (latest_info.lateral_kinematics_set.count(current_lanelet_data.lanelet) != 0) {
    const auto & lateral_kinematics =
      latest_info.lateral_kinematics_set.at(current_lanelet_data.lanelet);
    left_dist = lateral_kinematics.dist_from_left_boundary;
    right_dist = lateral_kinematics.dist_from_right_boundary;
    v_left_filtered = lateral_kinematics.filtered_left_lateral_velocity;
    v_right_filtered = lateral_kinematics.filtered_right_lateral_velocity;
    not_found_corresponding_lanelet = false;
  }

  // return lane follow when catch exception
  if (not_found_corresponding_lanelet) {
    return Maneuver::LANE_FOLLOW;
  }

  const double latest_lane_width = left_dist + right_dist;
  if (latest_lane_width < 1e-3) {
    RCLCPP_ERROR(get_logger(), "[Map Based Prediction]: Lane Width is too small");
    return Maneuver::LANE_FOLLOW;
  }

  // Step 4. check time to reach left/right bound
  const double epsilon = 1e-9;
  const double margin_to_reach_left_bound = left_dist / (std::fabs(v_left_filtered) + epsilon);
  const double margin_to_reach_right_bound = right_dist / (std::fabs(v_right_filtered) + epsilon);

  // Step 5. detect lane change
  if (
    left_dist < right_dist &&                              // in left side,
    left_dist < dist_threshold_to_bound_ &&                // close to boundary,
    v_left_filtered < 0 &&                                 // approaching,
    margin_to_reach_left_bound < time_threshold_to_bound_  // will soon arrive to left bound
  ) {
    return Maneuver::LEFT_LANE_CHANGE;
  } else if (
    right_dist < left_dist &&                               // in right side,
    right_dist < dist_threshold_to_bound_ &&                // close to boundary,
    v_right_filtered < 0 &&                                 // approaching,
    margin_to_reach_right_bound < time_threshold_to_bound_  // will soon arrive to right bound
  ) {
    return Maneuver::RIGHT_LANE_CHANGE;
  }

  return Maneuver::LANE_FOLLOW;
}

Maneuver MapBasedPredictionNode::predictObjectManeuverByLatDiffDistance(
  const std::string & object_id, const geometry_msgs::msg::Pose & object_pose,
  const LaneletData & current_lanelet_data, const double /*object_detected_time*/)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  // Step1. Check if we have the object in the buffer
  if (road_users_history_.count(object_id) == 0) {
    return Maneuver::LANE_FOLLOW;
  }

  const std::deque<RoadUser> & object_info = road_users_history_.at(object_id);
  const double current_time = (this->get_clock()->now()).seconds();

  // Step2. Get the previous id
  int prev_id = static_cast<int>(object_info.size()) - 1;
  while (prev_id >= 0) {
    const double prev_time_delay = object_info.at(prev_id).time_delay;
    const double prev_time =
      rclcpp::Time(object_info.at(prev_id).header.stamp).seconds() + prev_time_delay;
    // if (object_detected_time - prev_time > history_time_length_) {
    if (current_time - prev_time > history_time_length_) {
      break;
    }
    --prev_id;
  }

  if (prev_id < 0) {
    return Maneuver::LANE_FOLLOW;
  }

  // Step3. Get closest previous lanelet ID
  const auto & prev_info = object_info.at(static_cast<size_t>(prev_id));
  const auto prev_pose = prev_info.pose;
  const lanelet::ConstLanelets prev_lanelets =
    object_info.at(static_cast<size_t>(prev_id)).current_lanelets;
  if (prev_lanelets.empty()) {
    return Maneuver::LANE_FOLLOW;
  }
  lanelet::ConstLanelet prev_lanelet = prev_lanelets.front();
  double closest_prev_yaw = std::numeric_limits<double>::max();
  for (const auto & lanelet : prev_lanelets) {
    const double lane_yaw = autoware::experimental::lanelet2_utils::get_lanelet_angle(
      lanelet, autoware::experimental::lanelet2_utils::from_ros(prev_pose).basicPoint());
    const double delta_yaw = tf2::getYaw(prev_pose.orientation) - lane_yaw;
    const double normalized_delta_yaw = autoware_utils::normalize_radian(delta_yaw);
    if (normalized_delta_yaw < closest_prev_yaw) {
      closest_prev_yaw = normalized_delta_yaw;
      prev_lanelet = lanelet;
    }
  }

  // Step4. Check if the vehicle has changed lane
  const auto current_lanelet = current_lanelet_data.lanelet;
  const auto current_pose = object_pose;
  const double dist = autoware_utils::calc_distance2d(prev_pose, current_pose);
  lanelet::routing::LaneletPaths possible_paths =
    routing_graph_ptr_->possiblePaths(prev_lanelet, dist + 2.0, 0, false);
  bool has_lane_changed = true;
  if (prev_lanelet == current_lanelet) {
    has_lane_changed = false;
  } else {
    for (const auto & path : possible_paths) {
      for (const auto & lanelet : path) {
        if (lanelet == current_lanelet) {
          has_lane_changed = false;
          break;
        }
      }
    }
  }

  if (has_lane_changed) {
    return Maneuver::LANE_FOLLOW;
  }

  // Step5. Lane Change Detection
  const lanelet::ConstLineString2d prev_left_bound = prev_lanelet.leftBound2d();
  const lanelet::ConstLineString2d prev_right_bound = prev_lanelet.rightBound2d();
  const lanelet::ConstLineString2d current_left_bound = current_lanelet.leftBound2d();
  const lanelet::ConstLineString2d current_right_bound = current_lanelet.rightBound2d();
  const double prev_left_dist = calcLeftLateralOffset(prev_left_bound, prev_pose);
  const double prev_right_dist = calcRightLateralOffset(prev_right_bound, prev_pose);
  const double current_left_dist = calcLeftLateralOffset(current_left_bound, current_pose);
  const double current_right_dist = calcRightLateralOffset(current_right_bound, current_pose);
  const double prev_lane_width = std::fabs(prev_left_dist) + std::fabs(prev_right_dist);
  const double current_lane_width = std::fabs(current_left_dist) + std::fabs(current_right_dist);
  if (prev_lane_width < 1e-3 || current_lane_width < 1e-3) {
    RCLCPP_ERROR(get_logger(), "[Map Based Prediction]: Lane Width is too small");
    return Maneuver::LANE_FOLLOW;
  }

  const double current_left_dist_ratio = current_left_dist / current_lane_width;
  const double current_right_dist_ratio = current_right_dist / current_lane_width;
  const double diff_left_current_prev = current_left_dist - prev_left_dist;
  const double diff_right_current_prev = current_right_dist - prev_right_dist;

  if (
    current_left_dist_ratio > dist_ratio_threshold_to_left_bound_ &&
    diff_left_current_prev > diff_dist_threshold_to_left_bound_) {
    return Maneuver::LEFT_LANE_CHANGE;
  } else if (
    current_right_dist_ratio < dist_ratio_threshold_to_right_bound_ &&
    diff_right_current_prev < diff_dist_threshold_to_right_bound_) {
    return Maneuver::RIGHT_LANE_CHANGE;
  }

  return Maneuver::LANE_FOLLOW;
}

double get_lanelet_angle(
  const lanelet::ConstLanelet & lanelet, const lanelet::BasicPoint3d & search_pt)
{
  lanelet::ConstLineString3d segment = get_closest_segment(lanelet.centerline(), search_pt);
  return std::atan2(
    segment.back().y() - segment.front().y(), segment.back().x() - segment.front().x());
}

lanelet::ConstLineString3d get_closest_segment(
  const lanelet::ConstLineString3d & linestring, const lanelet::BasicPoint3d & search_pt)
{
  lanelet::ConstLineString3d closest_segment;
  double min_distance = std::numeric_limits<double>::max();

  for (const auto & [prev_pt, current_pt] :
       ranges::views::zip(linestring, linestring | ranges::views::drop(1))) {
    lanelet::Point3d prev_pt_3d(lanelet::InvalId, prev_pt.x(), prev_pt.y(), prev_pt.z());
    lanelet::Point3d current_pt_3d(
      lanelet::InvalId, current_pt.x(), current_pt.y(), current_pt.z());

    lanelet::ConstLineString3d current_segment(lanelet::InvalId, {prev_pt_3d, current_pt_3d});
    double distance = lanelet::geometry::distance3d(current_segment.basicLineString(), search_pt);
    if (distance < min_distance) {
      closest_segment = current_segment;
      min_distance = distance;
    }
  }
  return closest_segment;
}

double MapBasedPredictionNode::calcLeftLateralOffset(
  const lanelet::ConstLineString2d & boundary_line, const geometry_msgs::msg::Pose & search_pose)
{
  return -calcRightLateralOffset(boundary_line, search_pose);
}

double MapBasedPredictionNode::calcRightLateralOffset(
  const lanelet::ConstLineString2d & boundary_line, const geometry_msgs::msg::Pose & search_pose)
{
  std::vector<geometry_msgs::msg::Point> boundary_path(boundary_line.size());
  for (size_t i = 0; i < boundary_path.size(); ++i) {
    const double x = boundary_line[i].x();
    const double y = boundary_line[i].y();
    boundary_path[i] = autoware_utils::create_point(x, y, 0.0);
  }

  return std::fabs(autoware::motion_utils::calcLateralOffset(boundary_path, search_pose.position));
}

inline geometry_msgs::msg::Point create_point(const double x, const double y, const double z)
{
  geometry_msgs::msg::Point p;
  p.x = x;
  p.y = y;
  p.z = z;
  return p;
}

double calcLateralOffset(
  const T & points, const geometry_msgs::msg::Point & p_target, const bool throw_exception = false)
{
  const auto overlap_removed_points = removeOverlapPoints(points, 0);

  if (throw_exception) {
    validateNonEmpty(overlap_removed_points);
  } else {
    try {
      validateNonEmpty(overlap_removed_points);
    } catch (const std::exception & e) {
      RCLCPP_DEBUG(
        get_logger(),
        "%s Return NaN since no_throw option is enabled. The maintainer must check the code.",
        e.what());
      return std::nan("");
    }
  }

  if (overlap_removed_points.size() == 1) {
    const std::string error_message(
      "[autoware_motion_utils] " + std::string(__func__) +
      ": Lateral offset calculation is not supported for the same points.");
    autoware_utils_system::print_backtrace();
    if (throw_exception) {
      throw std::runtime_error(error_message);
    }
    RCLCPP_DEBUG(
      get_logger(),
      "%s Return NaN since no_throw option is enabled. The maintainer must check the code.",
      error_message.c_str());
    return std::nan("");
  }

  const size_t seg_idx = findNearestSegmentIndex(overlap_removed_points, p_target);
  return calcLateralOffset(points, p_target, seg_idx, throw_exception);
}

[[nodiscard]] T removeOverlapPoints(const T & points, const size_t start_idx = 0)
{
  if (points.size() < start_idx + 1) {
    return points;
  }

  T dst;
  dst.reserve(points.size());

  for (size_t i = 0; i <= start_idx; ++i) {
    dst.push_back(points.at(i));
  }

  constexpr double eps = 1.0E-08;
  for (size_t i = start_idx + 1; i < points.size(); ++i) {
    const auto prev_p = autoware_utils_geometry::get_point(dst.back());
    const auto curr_p = autoware_utils_geometry::get_point(points.at(i));
    if (std::abs(prev_p.x - curr_p.x) < eps && std::abs(prev_p.y - curr_p.y) < eps) {
      continue;
    }
    dst.push_back(points.at(i));
  }

  return dst;
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

size_t findNearestSegmentIndex(const T & points, const geometry_msgs::msg::Point & point)
{
  const size_t nearest_idx = findNearestIndex(points, point);

  if (nearest_idx == 0) {
    return 0;
  }
  if (nearest_idx == points.size() - 1) {
    return points.size() - 2;
  }

  const double signed_length = calcLongitudinalOffsetToSegment(points, nearest_idx, point);

  if (signed_length <= 0) {
    return nearest_idx - 1;
  }

  return nearest_idx;
}

[[nodiscard]] size_t findNearestIndex(const T & points, const geometry_msgs::msg::Point & point)
{
  validateNonEmpty(points);

  double min_dist = std::numeric_limits<double>::max();
  size_t min_idx = 0;

  for (size_t i = 0; i < points.size(); ++i) {
    const auto dist = autoware_utils_geometry::calc_squared_distance2d(points.at(i), point);
    if (dist < min_dist) {
      min_dist = dist;
      min_idx = i;
    }
  }
  return min_idx;
}

double calc_squared_distance2d(const Point1 & point1, const Point2 & point2)
{
  const auto p1 = get_point(point1);
  const auto p2 = get_point(point2);
  const auto dx = p1.x - p2.x;
  const auto dy = p1.y - p2.y;
  return dx * dx + dy * dy;
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

double calcLongitudinalOffsetToSegment(
  const T & points, const size_t seg_idx, const geometry_msgs::msg::Point & p_target,
  const bool throw_exception = false)
{
  if (seg_idx >= points.size() - 1) {
    const std::string error_message(
      "[autoware_motion_utils] " + std::string(__func__) +
      ": Failed to calculate longitudinal offset because the given segment index is out of the "
      "points size.");
    autoware_utils_system::print_backtrace();
    if (throw_exception) {
      throw std::out_of_range(error_message);
    }
    RCLCPP_DEBUG(
      get_logger(),
      "%s Return NaN since no_throw option is enabled. The maintainer must check the code.",
      error_message.c_str());
    return std::nan("");
  }

  const auto overlap_removed_points = removeOverlapPoints(points, seg_idx);

  if (throw_exception) {
    validateNonEmpty(overlap_removed_points);
  } else {
    try {
      validateNonEmpty(overlap_removed_points);
    } catch (const std::exception & e) {
      RCLCPP_DEBUG(get_logger(), "%s", e.what());
      return std::nan("");
    }
  }

  if (seg_idx >= overlap_removed_points.size() - 1) {
    const std::string error_message(
      "[autoware_motion_utils] " + std::string(__func__) +
      ": Longitudinal offset calculation is not supported for the same points.");
    autoware_utils_system::print_backtrace();
    if (throw_exception) {
      throw std::runtime_error(error_message);
    }
    RCLCPP_DEBUG(
      get_logger(),
      "%s Return NaN since no_throw option is enabled. The maintainer must check the code.",
      error_message.c_str());
    return std::nan("");
  }

  const auto p_front = autoware_utils_geometry::get_point(overlap_removed_points.at(seg_idx));
  const auto p_back = autoware_utils_geometry::get_point(overlap_removed_points.at(seg_idx + 1));

  const Eigen::Vector3d segment_vec{p_back.x - p_front.x, p_back.y - p_front.y, 0};
  const Eigen::Vector3d target_vec{p_target.x - p_front.x, p_target.y - p_front.y, 0};

  return segment_vec.dot(target_vec) / segment_vec.norm();
}

[[nodiscard]] T removeOverlapPoints(const T & points, const size_t start_idx = 0)
{
  if (points.size() < start_idx + 1) {
    return points;
  }

  T dst;
  dst.reserve(points.size());

  for (size_t i = 0; i <= start_idx; ++i) {
    dst.push_back(points.at(i));
  }

  constexpr double eps = 1.0E-08;
  for (size_t i = start_idx + 1; i < points.size(); ++i) {
    const auto prev_p = autoware_utils_geometry::get_point(dst.back());
    const auto curr_p = autoware_utils_geometry::get_point(points.at(i));
    if (std::abs(prev_p.x - curr_p.x) < eps && std::abs(prev_p.y - curr_p.y) < eps) {
      continue;
    }
    dst.push_back(points.at(i));
  }

  return dst;
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

ManeuverProbability MapBasedPredictionNode::calculateManeuverProbability(
  const Maneuver & predicted_maneuver, const bool & left_paths_exists,
  const bool & right_paths_exists, const bool & center_paths_exists) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  float left_lane_change_probability = 0.0;
  float right_lane_change_probability = 0.0;
  float lane_follow_probability = 0.0;
  if (left_paths_exists && predicted_maneuver == Maneuver::LEFT_LANE_CHANGE) {
    constexpr float LF_PROB_WHEN_LC = 0.9;  // probability for lane follow during lane change
    constexpr float LC_PROB_WHEN_LC = 1.0;  // probability for left lane change
    left_lane_change_probability = LC_PROB_WHEN_LC;
    right_lane_change_probability = 0.0;
    lane_follow_probability = LF_PROB_WHEN_LC;
  } else if (right_paths_exists && predicted_maneuver == Maneuver::RIGHT_LANE_CHANGE) {
    constexpr float LF_PROB_WHEN_LC = 0.9;  // probability for lane follow during lane change
    constexpr float RC_PROB_WHEN_LC = 1.0;  // probability for right lane change
    left_lane_change_probability = 0.0;
    right_lane_change_probability = RC_PROB_WHEN_LC;
    lane_follow_probability = LF_PROB_WHEN_LC;
  } else if (center_paths_exists) {
    constexpr float LF_PROB = 1.0;  // probability for lane follow
    constexpr float LC_PROB = 0.3;  // probability for left lane change
    constexpr float RC_PROB = 0.3;  // probability for right lane change
    if (predicted_maneuver == Maneuver::LEFT_LANE_CHANGE) {
      // If prediction says left change, but left lane is empty, assume lane follow
      left_lane_change_probability = 0.0;
      right_lane_change_probability = (right_paths_exists) ? RC_PROB : 0.0;
    } else if (predicted_maneuver == Maneuver::RIGHT_LANE_CHANGE) {
      // If prediction says right change, but right lane is empty, assume lane follow
      left_lane_change_probability = (left_paths_exists) ? LC_PROB : 0.0;
      right_lane_change_probability = 0.0;
    } else {
      // Predicted Maneuver is Lane Follow
      left_lane_change_probability = LC_PROB;
      right_lane_change_probability = RC_PROB;
    }
    lane_follow_probability = LF_PROB;
  } else {
    // Center path is empty
    constexpr float LC_PROB = 1.0;  // probability for left lane change
    constexpr float RC_PROB = 1.0;  // probability for right lane change
    lane_follow_probability = 0.0;

    // If the given lane is empty, the probability goes to 0
    left_lane_change_probability = left_paths_exists ? LC_PROB : 0.0;
    right_lane_change_probability = right_paths_exists ? RC_PROB : 0.0;
  }

  const float MIN_PROBABILITY = 1e-3;
  const float max_prob = std::max(
    MIN_PROBABILITY, std::max(
                       lane_follow_probability,
                       std::max(left_lane_change_probability, right_lane_change_probability)));

  // Insert Normalized Probability
  ManeuverProbability maneuver_prob;
  maneuver_prob[Maneuver::LEFT_LANE_CHANGE] = left_lane_change_probability / max_prob;
  maneuver_prob[Maneuver::RIGHT_LANE_CHANGE] = right_lane_change_probability / max_prob;
  maneuver_prob[Maneuver::LANE_FOLLOW] = lane_follow_probability / max_prob;

  return maneuver_prob;
}

PredictedPath PathGenerator::generatePathForOnLaneVehicle(
  const TrackedObject & object, const PosePath & ref_path, const double duration,
  const double lateral_duration, const double path_width, const double speed_limit) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  if (ref_path.size() < 2) {
    return generateStraightPath(object, duration);
  }

  // if the object is moving backward, we generate a straight path
  if (object.kinematics.twist_with_covariance.twist.linear.x < 0.0) {
    return generateStraightPath(object, duration);
  }

  // get object width
  double object_width = 5.0;  // a large number
  if (object.shape.type == autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    object_width = object.shape.dimensions.y;
  } else if (object.shape.type == autoware_perception_msgs::msg::Shape::CYLINDER) {
    object_width = object.shape.dimensions.x;
  }
  // Calculate the backlash width, which represents the maximum distance the object can be biased
  // from the reference path
  constexpr double margin =
    0.5;  // Set a safety margin of 0.5m for the object to stay away from the edge of the lane
  double backlash_width = (path_width - object_width) / 2.0 - margin;
  backlash_width = std::max(backlash_width, 0.0);  // minimum is 0.0

  return generatePolynomialPath(
    object, ref_path, duration, lateral_duration, path_width, backlash_width, speed_limit);
}

PredictedPath PathGenerator::generateStraightPath(
  const TrackedObject & object, const double longitudinal_duration) const
{
  const auto & object_pose = object.kinematics.pose_with_covariance.pose;
  const auto & object_twist = object.kinematics.twist_with_covariance.twist;
  constexpr double ep = 0.001;
  const double duration = longitudinal_duration + ep;

  PredictedPath path;
  path.time_step = rclcpp::Duration::from_seconds(sampling_time_interval_);
  path.path.reserve(static_cast<size_t>((duration) / sampling_time_interval_));
  for (double dt = 0.0; dt < duration; dt += sampling_time_interval_) {
    const auto future_obj_pose = autoware_utils::calc_offset_pose(
      object_pose, object_twist.linear.x * dt, object_twist.linear.y * dt, 0.0);
    path.path.push_back(future_obj_pose);
  }

  return path;
}

geometry_msgs::msg::Pose calc_offset_pose(
  const geometry_msgs::msg::Pose & p, const double x, const double y, const double z,
  const double yaw)
{
  geometry_msgs::msg::Pose pose;
  geometry_msgs::msg::Transform transform;
  transform.translation = create_translation(x, y, z);
  transform.rotation = create_quaternion_from_yaw(yaw);
  tf2::Transform tf_pose;
  tf2::Transform tf_offset;
  tf2::fromMsg(transform, tf_offset);
  tf2::fromMsg(p, tf_pose);
  tf2::toMsg(tf_pose * tf_offset, pose);
  return pose;
}

geometry_msgs::msg::Vector3 create_translation(const double x, const double y, const double z)
{
  geometry_msgs::msg::Vector3 v;
  v.x = x;
  v.y = y;
  v.z = z;
  return v;
}

geometry_msgs::msg::Quaternion create_quaternion_from_yaw(const double yaw)
{
  tf2::Quaternion q;
  q.setRPY(0, 0, yaw);
  return tf2::toMsg(q);
}

PredictedPath PathGenerator::generatePolynomialPath(
  const TrackedObject & object, const PosePath & ref_path, const double duration,
  const double lateral_duration, const double path_width, const double backlash_width,
  const double speed_limit) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  // Get current Frenet Point
  const double ref_path_len = autoware::motion_utils::calcArcLength(ref_path);
  const auto current_point = getFrenetPoint(object, ref_path.at(0), duration, speed_limit);

  // Step 1. Set Target Frenet Point
  // Note that we do not set position s,
  // since we don't know the target longitudinal position
  FrenetPoint terminal_point;
  terminal_point.s_vel = std::hypot(current_point.s_vel, current_point.d_vel);
  terminal_point.s_acc = 0.0;
  terminal_point.d_vel = 0.0;
  terminal_point.d_acc = 0.0;

  // if the object is behind of the reference path adjust the lateral_duration to reach the start of
  // the reference path
  double lateral_duration_adjusted = lateral_duration;
  if (current_point.s < 0.0) {
    const double distance_to_start = -current_point.s;
    const double duration_to_reach = distance_to_start / terminal_point.s_vel;
    lateral_duration_adjusted = std::max(lateral_duration, duration_to_reach);
  }

  // calculate terminal d position, based on backlash width
  {
    if (backlash_width < 0.01 /*m*/) {
      // If the backlash width is less than 0.01m, do not consider the backlash width and reduce
      // calculation cost
      terminal_point.d = 0.0;
    } else {
      const double return_width = path_width / 2.0;  // [m]
      const double current_momentum_d =
        current_point.d + 0.5 * current_point.d_vel * lateral_duration_adjusted;
      const double momentum_d_abs = std::abs(current_momentum_d);

      if (momentum_d_abs < backlash_width) {
        // If the object momentum is within the backlash width, we set the target d position to the
        // current momentum
        terminal_point.d = current_momentum_d;
      } else if (
        momentum_d_abs >= backlash_width && momentum_d_abs < backlash_width + return_width) {
        // If the object momentum is within the return zone, we set the target d position close to
        // the zero gradually
        terminal_point.d =
          (backlash_width + return_width - momentum_d_abs) * backlash_width / return_width;
        terminal_point.d *= (current_momentum_d > 0) ? 1 : -1;
      } else {
        // If the object momentum is outside the backlash width + return zone, we set the target d
        // position to 0
        terminal_point.d = 0.0;
      }
    }
  }

  // Step 2. Generate Predicted Path on a Frenet coordinate
  const auto frenet_predicted_path = generateFrenetPath(
    current_point, terminal_point, ref_path_len, duration, lateral_duration_adjusted);

  // Step 3. Interpolate Reference Path for converting predicted path coordinate
  const auto interpolated_ref_path = interpolateReferencePath(ref_path, frenet_predicted_path);

  if (frenet_predicted_path.size() < 2 || interpolated_ref_path.size() < 2) {
    return generateStraightPath(object, duration);
  }

  // Step 4. Convert predicted trajectory from Frenet to Cartesian coordinate
  return convertToPredictedPath(object, frenet_predicted_path, interpolated_ref_path);
}

FrenetPoint PathGenerator::getFrenetPoint(
  const TrackedObject & object, const geometry_msgs::msg::Pose & ref_pose, const double duration,
  const double speed_limit) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  FrenetPoint frenet_point;

  // 1. Position
  const auto obj_point = object.kinematics.pose_with_covariance.pose.position;
  const float obj_yaw =
    static_cast<float>(tf2::getYaw(object.kinematics.pose_with_covariance.pose.orientation));
  const float lane_yaw = static_cast<float>(tf2::getYaw(ref_pose.orientation));
  frenet_point.s = (obj_point.x - ref_pose.position.x) * cos(lane_yaw) +
                   (obj_point.y - ref_pose.position.y) * sin(lane_yaw);
  frenet_point.d = -(obj_point.x - ref_pose.position.x) * sin(lane_yaw) +
                   (obj_point.y - ref_pose.position.y) * cos(lane_yaw);

  // 2. Velocity (adjusted by acceleration)
  const float vx = static_cast<float>(object.kinematics.twist_with_covariance.twist.linear.x);
  const float vy = static_cast<float>(object.kinematics.twist_with_covariance.twist.linear.y);
  const float ax =
    (use_vehicle_acceleration_)
      ? static_cast<float>(object.kinematics.acceleration_with_covariance.accel.linear.x)
      : 0.0;
  const float ay =
    (use_vehicle_acceleration_)
      ? static_cast<float>(object.kinematics.acceleration_with_covariance.accel.linear.y)
      : 0.0;
  const float delta_yaw = obj_yaw - lane_yaw;

  // using a decaying acceleration model. Consult the README for more information about the model.
  const double t_h = duration;
  const float lambda = std::log(2) / acceleration_exponential_half_life_;

  auto have_same_sign = [](double a, double b) -> bool {
    return (a >= 0.0 && b >= 0.0) || (a < 0.0 && b < 0.0);
  };

  auto get_acceleration_adjusted_velocity = [&](const double v, const double a) {
    constexpr double epsilon = 1E-5;
    if (std::abs(a) < epsilon) {
      // Assume constant speed
      return v;
    }
    // Get velocity after time horizon
    const auto terminal_velocity = v + a * (1.0 / lambda) * (1 - std::exp(-lambda * t_h));

    const auto lambda_2 = lambda * lambda;

    // If vehicle is decelerating, make sure its speed does not change signs (we assume it will, at
    // most stop, not reverse its direction)
    if (!have_same_sign(terminal_velocity, v)) {
      // we assume a forwards moving vehicle will not decelerate to 0 and then move backwards
      // if the velocities don't have the same sign, calculate when the vehicle reaches 0 speed ->
      // time t_stop

      // 0 = Vo + acc(1/lambda)(1-e^(-lambda t_stop))
      // e^(-lambda t_stop) = 1 - (-Vo* lambda)/acc
      // t_stop = (-1/lambda)*ln(1 - (-Vo* lambda)/acc)
      // t_stop = (-1/lambda)*ln(1 + (Vo* lambda)/acc)
      auto t_stop = (-1.0 / lambda) * std::log1p(v * lambda / a);

      // Calculate the distance traveled until stopping
      auto distance_to_reach_zero_speed =
        v * t_stop + a * t_stop * (1.0 / lambda) + a * (1.0 / lambda_2) * std::expm1(-lambda * t_h);
      // Output an equivalent constant speed
      return distance_to_reach_zero_speed / t_h;
    }

    // if the vehicle speed limit is not surpassed we return an equivalent speed = x(T) / T
    // alternatively, if the vehicle is still accelerating and has surpassed the speed limit.
    // assume it will continue accelerating (reckless driving)
    const bool object_has_surpassed_limit_already = v > speed_limit;
    if (terminal_velocity < speed_limit || object_has_surpassed_limit_already)
      return v + a * (1.0 / lambda) + (a / (t_h * lambda_2)) * std::expm1(-lambda * t_h);

    // It is assumed the vehicle accelerates until final_speed is reached and
    // then continues at constant speed for the rest of the time horizon
    // So, we calculate the time it takes to reach the speed limit and compute how far the vehicle
    // would go if it accelerated until reaching the speed limit, and then continued at a constant
    // speed.
    const double t_f = (-1.0 / lambda) * std::log(1 - ((speed_limit - v) * lambda) / a);
    const double distance_covered =
      // Distance covered while accelerating
      a * (1.0 / lambda) * t_f + a * (1.0 / lambda_2) * std::expm1(-lambda * t_f) + v * t_f +
      // Distance covered at constant speed for the rest of the horizon time
      speed_limit * (t_h - t_f);
    return distance_covered / t_h;
  };

  const float acceleration_adjusted_velocity_x = get_acceleration_adjusted_velocity(vx, ax);
  const float acceleration_adjusted_velocity_y = get_acceleration_adjusted_velocity(vy, ay);
  frenet_point.s_vel = acceleration_adjusted_velocity_x * std::cos(delta_yaw) -
                       acceleration_adjusted_velocity_y * std::sin(delta_yaw);
  frenet_point.d_vel = acceleration_adjusted_velocity_x * std::sin(delta_yaw) +
                       acceleration_adjusted_velocity_y * std::cos(delta_yaw);

  // 3. Acceleration, assuming constant acceleration
  frenet_point.s_acc = 0.0;
  frenet_point.d_acc = 0.0;

  return frenet_point;
}

auto get_acceleration_adjusted_velocity = [&](const double v, const double a) {
  constexpr double epsilon = 1E-5;
  if (std::abs(a) < epsilon) {
    // Assume constant speed
    return v;
  }
  // Get velocity after time horizon
  const auto terminal_velocity = v + a * (1.0 / lambda) * (1 - std::exp(-lambda * t_h));

  const auto lambda_2 = lambda * lambda;

  // If vehicle is decelerating, make sure its speed does not change signs (we assume it will, at
  // most stop, not reverse its direction)
  if (!have_same_sign(terminal_velocity, v)) {
    // we assume a forwards moving vehicle will not decelerate to 0 and then move backwards
    // if the velocities don't have the same sign, calculate when the vehicle reaches 0 speed ->
    // time t_stop

    // 0 = Vo + acc(1/lambda)(1-e^(-lambda t_stop))
    // e^(-lambda t_stop) = 1 - (-Vo* lambda)/acc
    // t_stop = (-1/lambda)*ln(1 - (-Vo* lambda)/acc)
    // t_stop = (-1/lambda)*ln(1 + (Vo* lambda)/acc)
    auto t_stop = (-1.0 / lambda) * std::log1p(v * lambda / a);

    // Calculate the distance traveled until stopping
    auto distance_to_reach_zero_speed =
      v * t_stop + a * t_stop * (1.0 / lambda) + a * (1.0 / lambda_2) * std::expm1(-lambda * t_h);
    // Output an equivalent constant speed
    return distance_to_reach_zero_speed / t_h;
  }

  // if the vehicle speed limit is not surpassed we return an equivalent speed = x(T) / T
  // alternatively, if the vehicle is still accelerating and has surpassed the speed limit.
  // assume it will continue accelerating (reckless driving)
  const bool object_has_surpassed_limit_already = v > speed_limit;
  if (terminal_velocity < speed_limit || object_has_surpassed_limit_already)
    return v + a * (1.0 / lambda) + (a / (t_h * lambda_2)) * std::expm1(-lambda * t_h);

  // It is assumed the vehicle accelerates until final_speed is reached and
  // then continues at constant speed for the rest of the time horizon
  // So, we calculate the time it takes to reach the speed limit and compute how far the vehicle
  // would go if it accelerated until reaching the speed limit, and then continued at a constant
  // speed.
  const double t_f = (-1.0 / lambda) * std::log(1 - ((speed_limit - v) * lambda) / a);
  const double distance_covered =
    // Distance covered while accelerating
    a * (1.0 / lambda) * t_f + a * (1.0 / lambda_2) * std::expm1(-lambda * t_f) + v * t_f +
    // Distance covered at constant speed for the rest of the horizon time
    speed_limit * (t_h - t_f);
  return distance_covered / t_h;
};

FrenetPath PathGenerator::generateFrenetPath(
  const FrenetPoint & current_point, const FrenetPoint & target_point, const double max_length,
  const double duration, const double lateral_duration) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  FrenetPath path;

  // Compute Lateral and Longitudinal Coefficients to generate the trajectory
  const Eigen::Vector3d lat_coeff =
    calcLatCoefficients(current_point, target_point, lateral_duration);
  const Eigen::Vector2d lon_coeff = calcLonCoefficients(current_point, target_point, duration);

  // Generate the trajectory
  path.reserve(static_cast<size_t>(duration / sampling_time_interval_));
  for (double t = 0.0; t <= duration; t += sampling_time_interval_) {
    const auto t2 = t * t;
    const auto t3 = t2 * t;
    const auto t4 = t3 * t;
    const auto t5 = t4 * t;
    const double current_acc =
      0.0;  // Currently we assume the object is traveling at a constant speed
    const double d_next_ = current_point.d + current_point.d_vel * t + current_acc * 2.0 * t2 +
                           lat_coeff(0) * t3 + lat_coeff(1) * t4 + lat_coeff(2) * t5;
    // t > lateral_duration: target_point.d, else d_next_
    const double d_next = t > lateral_duration ? target_point.d : d_next_;
    const double s_next = current_point.s + current_point.s_vel * t + 2.0 * current_acc * t2 +
                          lon_coeff(0) * t3 + lon_coeff(1) * t4;

    if (s_next > max_length) {
      break;
    }

    // Fill the FrenetPoint, velocity and acceleration are not used in the path generator
    FrenetPoint point;
    point.s = s_next;
    point.d = d_next;
    path.push_back(point);
  }

  return path;
}

Eigen::Vector3d PathGenerator::calcLatCoefficients(
  const FrenetPoint & current_point, const FrenetPoint & target_point, const double T) const
{
  // Lateral Path Calculation
  // Quintic polynomial for d
  // A = np.array([[T**3, T**4, T**5],
  //               [3 * T ** 2, 4 * T ** 3, 5 * T ** 4],
  //               [6 * T, 12 * T ** 2, 20 * T ** 3]])
  // A_inv = np.matrix([[10/(T**3), -4/(T**2), 1/(2*T)],
  //                    [-15/(T**4), 7/(T**3), -1/(T**2)],
  //                    [6/(T**5), -3/(T**4),  1/(2*T**3)]])
  // b = np.matrix([[xe - self.a0 - self.a1 * T - self.a2 * T**2],
  //                [vxe - self.a1 - 2 * self.a2 * T],
  //                [axe - 2 * self.a2]])
  const auto T2 = T * T;
  const auto T3 = T2 * T;
  const auto T4 = T3 * T;
  const auto T5 = T4 * T;

  Eigen::Matrix3d A_lat_inv;
  A_lat_inv << 10 / T3, -4 / T2, 1 / (2 * T), -15 / T4, 7 / T3, -1 / T2, 6 / T5, -3 / T4,
    1 / (2 * T3);
  Eigen::Vector3d b_lat;
  b_lat[0] = target_point.d - current_point.d - current_point.d_vel * T;
  b_lat[1] = target_point.d_vel - current_point.d_vel;
  b_lat[2] = target_point.d_acc;

  return A_lat_inv * b_lat;
}

Eigen::Vector2d PathGenerator::calcLonCoefficients(
  const FrenetPoint & current_point, const FrenetPoint & target_point, const double T) const
{
  // Longitudinal Path Calculation
  // Quadric polynomial
  // A_inv = np.matrix([[1/(T**2), -1/(3*T)],
  //                         [-1/(2*T**3), 1/(4*T**2)]])
  // b = np.matrix([[vxe - self.a1 - 2 * self.a2 * T],
  //               [axe - 2 * self.a2]])
  const auto T2 = T * T;
  const auto T3 = T2 * T;

  Eigen::Matrix2d A_lon_inv;
  A_lon_inv << 1 / T2, -1 / (3 * T), -1 / (2 * T3), 1 / (4 * T2);
  Eigen::Vector2d b_lon;
  b_lon[0] = target_point.s_vel - current_point.s_vel;
  b_lon[1] = 0.0;
  return A_lon_inv * b_lon;
}

PosePath PathGenerator::interpolateReferencePath(
  const PosePath & base_path, const FrenetPath & frenet_predicted_path) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  PosePath interpolated_path;
  const size_t interpolate_num = frenet_predicted_path.size();
  if (interpolate_num < 2) {
    interpolated_path.emplace_back(base_path.front());
    return interpolated_path;
  }

  // Prepare base path vectors
  std::vector<double> base_path_x(base_path.size());
  std::vector<double> base_path_y(base_path.size());
  std::vector<double> base_path_z(base_path.size());
  std::vector<tf2::Quaternion> base_path_orientation(base_path.size());
  std::vector<double> base_path_s(base_path.size(), 0.0);
  for (size_t i = 0; i < base_path.size(); ++i) {
    base_path_x.at(i) = base_path.at(i).position.x;
    base_path_y.at(i) = base_path.at(i).position.y;
    base_path_z.at(i) = base_path.at(i).position.z;
    tf2::Quaternion src_tf;
    tf2::fromMsg(base_path.at(i).orientation, src_tf);
    base_path_orientation.at(i) = src_tf;
    if (i > 0) {
      base_path_s.at(i) = base_path_s.at(i - 1) +
                          autoware_utils::calc_distance2d(base_path.at(i - 1), base_path.at(i));
    }
  }

  // Prepare resampled s vector
  std::vector<double> resampled_s(frenet_predicted_path.size());
  for (size_t i = 0; i < frenet_predicted_path.size(); ++i) {
    resampled_s.at(i) = frenet_predicted_path.at(i).s;
  }

  // Linear Interpolation for x, y, z, and orientation
  std::vector<double> lerp_ref_path_x = interpolationLerp(base_path_s, base_path_x, resampled_s);
  std::vector<double> lerp_ref_path_y = interpolationLerp(base_path_s, base_path_y, resampled_s);
  std::vector<double> lerp_ref_path_z = interpolationLerp(base_path_s, base_path_z, resampled_s);
  std::vector<tf2::Quaternion> lerp_ref_path_orientation =
    interpolationLerp(base_path_s, base_path_orientation, resampled_s);

  // Set the interpolated PosePath
  interpolated_path.resize(interpolate_num);
  for (size_t i = 0; i < interpolate_num; ++i) {
    geometry_msgs::msg::Pose interpolated_pose;
    interpolated_pose.position = autoware_utils::create_point(
      lerp_ref_path_x.at(i), lerp_ref_path_y.at(i), lerp_ref_path_z.at(i));
    interpolated_pose.orientation = tf2::toMsg(lerp_ref_path_orientation.at(i));
    interpolated_path.at(i) = interpolated_pose;
  }

  return interpolated_path;
}

double calc_distance2d(const Point1 & point1, const Point2 & point2)
{
  const auto p1 = get_point(point1);
  const auto p2 = get_point(point2);
  return std::hypot(p1.x - p2.x, p1.y - p2.y);
}

geometry_msgs::msg::Point get_point(const T & p)
{
  return geometry_msgs::build<geometry_msgs::msg::Point>().x(p.x).y(p.y).z(p.z);
}

std::vector<double> PathGenerator::interpolationLerp(
  const std::vector<double> & base_keys, const std::vector<double> & base_values,
  const std::vector<double> & query_keys) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_)
    st_ptr = std::make_unique<ScopedTimeTrack>("interpolationLerp_double", *time_keeper_);

  // calculate linear interpolation
  // extrapolate the value if the query key is out of the base key range
  std::vector<double> query_values;
  size_t key_index = 0;
  double last_query_key = query_keys.at(0);
  for (const auto query_key : query_keys) {
    // search for the closest key index
    // if current query key is larger than the last query key, search base_keys increasing order
    if (query_key >= last_query_key) {
      while (base_keys.at(key_index + 1) < query_key) {
        if (key_index == base_keys.size() - 2) {
          break;
        }
        ++key_index;
      }
    } else {
      // if current query key is smaller than the last query key, search base_keys decreasing order
      while (base_keys.at(key_index) > query_key) {
        if (key_index == 0) {
          break;
        }
        --key_index;
      }
    }
    last_query_key = query_key;

    const double & src_val = base_values.at(key_index);
    const double & dst_val = base_values.at(key_index + 1);
    const double ratio = (query_key - base_keys.at(key_index)) /
                         (base_keys.at(key_index + 1) - base_keys.at(key_index));

    const double interpolated_val = src_val + (dst_val - src_val) * ratio;
    query_values.push_back(interpolated_val);
  }

  return query_values;
}

inline geometry_msgs::msg::Point create_point(const double x, const double y, const double z)
{
  geometry_msgs::msg::Point p;
  p.x = x;
  p.y = y;
  p.z = z;
  return p;
}

PredictedPath PathGenerator::convertToPredictedPath(
  const TrackedObject & object, const FrenetPath & frenet_predicted_path,
  const PosePath & ref_path) const
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  // Object position
  const auto & object_pose = object.kinematics.pose_with_covariance.pose;
  const double object_height = object.shape.dimensions.z / 2.0;

  // Convert Frenet Path to Cartesian Path
  PredictedPath predicted_path;
  predicted_path.time_step = rclcpp::Duration::from_seconds(sampling_time_interval_);
  predicted_path.path.resize(ref_path.size());

  // Set the first point as the object's current position
  predicted_path.path.at(0) = object_pose;

  // Convert the rest of the points
  for (size_t i = 1; i < predicted_path.path.size(); ++i) {
    // Reference Point from interpolated reference path
    const auto & ref_pose = ref_path.at(i);

    // Frenet Point from frenet predicted path
    const auto & frenet_point = frenet_predicted_path.at(i);
    double d_offset = frenet_point.d;

    // Converted Pose
    auto predicted_pose = autoware_utils::calc_offset_pose(ref_pose, 0.0, d_offset, 0.0);
    predicted_pose.position.z += object_height;
    const double yaw = autoware_utils::calc_azimuth_angle(
      predicted_path.path.at(i - 1).position, predicted_pose.position);
    predicted_pose.orientation = autoware_utils::create_quaternion_from_yaw(yaw);

    predicted_path.path.at(i) = predicted_pose;
  }

  return predicted_path;
}

geometry_msgs::msg::Pose calc_offset_pose(
  const geometry_msgs::msg::Pose & p, const double x, const double y, const double z,
  const double yaw)
{
  geometry_msgs::msg::Pose pose;
  geometry_msgs::msg::Transform transform;
  transform.translation = create_translation(x, y, z);
  transform.rotation = create_quaternion_from_yaw(yaw);
  tf2::Transform tf_pose;
  tf2::Transform tf_offset;
  tf2::fromMsg(transform, tf_offset);
  tf2::fromMsg(p, tf_pose);
  tf2::toMsg(tf_pose * tf_offset, pose);
  return pose;
}

geometry_msgs::msg::Vector3 create_translation(const double x, const double y, const double z)
{
  geometry_msgs::msg::Vector3 v;
  v.x = x;
  v.y = y;
  v.z = z;
  return v;
}

geometry_msgs::msg::Quaternion create_quaternion_from_yaw(const double yaw)
{
  tf2::Quaternion q;
  q.setRPY(0, 0, yaw);
  return tf2::toMsg(q);
}

double calc_azimuth_angle(
  const geometry_msgs::msg::Point & p_from, const geometry_msgs::msg::Point & p_to)
{
  const double dx = p_to.x - p_from.x;
  const double dy = p_to.y - p_from.y;
  return std::atan2(dy, dx);
}

geometry_msgs::msg::Quaternion create_quaternion_from_yaw(const double yaw)
{
  tf2::Quaternion q;
  q.setRPY(0, 0, yaw);
  return tf2::toMsg(q);
}
